mapper.select:
SELECT COALESCE(SUM(cm.chatCount), 0) as chatCount, COALESCE(SUM(cm.inputTokens), 0) as inputTokens, COALESCE(SUM(cm.outputTokens), 0) as outputTokens, COALESCE(SUM(gc.imageCount), 0) as imageCount, COALESCE(SUM(gc.videoCount), 0) as videoCount, COALESCE(SUM(arl.relayCount), 0) as relayCount, COALESCE(SUM(arl.relayInputTokens), 0) as relayInputTokens, COALESCE(SUM(arl.relayOutputTokens), 0) as relayOutputTokens FROM sys_user u -- 子查询1：聊天消息统计 LEFT JOIN ( SELECT cs.user_id, COUNT(cm.id) as chatCount, SUM(cm.input_tokens) as inputTokens, SUM(cm.output_tokens) as outputTokens FROM chat_session cs LEFT JOIN chat_message cm ON cs.session_id = cm.session_id AND cm.role = 'assistant'
AND DATE(cm.create_time) BETWEEN #{startDate} AND #{endDate}
GROUP BY cs.user_id ) cm ON u.id = cm.user_id -- 子查询2：生成内容统计 LEFT JOIN ( SELECT user_id, SUM(CASE WHEN type = 'image' THEN 1 ELSE 0 END) as imageCount, SUM(CASE WHEN type = 'video' THEN 1 ELSE 0 END) as videoCount FROM ai_generated_content WHERE status = 1
AND DATE(create_time) BETWEEN #{startDate} AND #{endDate}
GROUP BY user_id ) gc ON u.id = gc.user_id -- 子查询3：API 转发统计 LEFT JOIN ( SELECT user_id, COUNT(id) as relayCount, SUM(input_tokens) as relayInputTokens, SUM(output_tokens) as relayOutputTokens FROM api_relay_log WHERE 1=1
AND DATE(create_time) BETWEEN #{startDate} AND #{endDate}
GROUP BY user_id ) arl ON u.id = arl.user_id WHERE u.deleted = 0
AND u.id = #{userId}
-- 关键：userId为null时汇总所有，为单个值时自然只有一行
GROUP BY NULL
